func (this *WeexCore) ParseTicker(ticker any, optionalArgs ...any) any {
	//
	// spot
	//     {
	//         "symbol": "ETHUSDT",
	//         "priceChange": "-72.98",
	//         "priceChangePercent": "-0.033811",
	//         "lastPrice": "2085.46",
	//         "bidPrice": "2085.44",
	//         "bidQty": "1.53848",
	//         "askPrice": "2085.47",
	//         "askQty": "1.87504",
	//         "openPrice": "2158.44",
	//         "highPrice": "2168.40",
	//         "lowPrice": "2061.12",
	//         "volume": "157359.56105",
	//         "quoteVolume": "331284305.7193626",
	//         "openTime": 1775493000000,
	//         "closeTime": 1775579400000,
	//         "count": 59727
	//     }
	//
	// swap
	//     {
	//         "symbol": "ETHUSDT",
	//         "priceChange": "-75.49",
	//         "priceChangePercent": "-0.034992",
	//         "lastPrice": "2081.80",
	//         "openPrice": "2157.29",
	//         "highPrice": "2167.51",
	//         "lowPrice": "2059.17",
	//         "volume": "623160.426",
	//         "quoteVolume": "1310647345.19346",
	//         "openTime": 1775493000000,
	//         "closeTime": 1775579400000,
	//         "markPrice": "2081.8",
	//         "indexPrice": "2082.75"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(ticker, "symbol")
	var markPrice any = this.SafeString(ticker, "markPrice")
	var marketType any = "spot"
	if IsTrue(!IsEqual(markPrice, nil)) {
		marketType = "swap"
	}
	market = this.SafeMarket(marketId, market, nil, marketType)
	var timestamp any = this.SafeInteger2(ticker, "closeTime", "time")
	return this.SafeTicker(map[string]any{
		"symbol":        GetValue(market, "symbol"),
		"timestamp":     timestamp,
		"datetime":      this.Iso8601(timestamp),
		"high":          this.SafeString(ticker, "highPrice"),
		"low":           this.SafeString(ticker, "lowPrice"),
		"bid":           this.SafeString(ticker, "bidPrice"),
		"bidVolume":     this.SafeString(ticker, "bidQty"),
		"ask":           this.SafeString(ticker, "askPrice"),
		"askVolume":     this.SafeString(ticker, "askQty"),
		"vwap":          nil,
		"open":          this.SafeString(ticker, "openPrice"),
		"close":         this.SafeString(ticker, "lastPrice"),
		"last":          this.SafeString(ticker, "lastPrice"),
		"previousClose": nil,
		"change":        this.SafeString(ticker, "priceChange"),
		"percentage":    this.SafeString(ticker, "priceChangePercent"),
		"average":       nil,
		"baseVolume":    this.SafeString(ticker, "volume"),
		"quoteVolume":   this.SafeString(ticker, "quoteVolume"),
		"markPrice":     markPrice,
		"indexPrice":    this.SafeString(ticker, "indexPrice"),
		"info":          ticker,
	}, market)
}

