func (this *WeexCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchTrades
	//     {
	//         "id": "875fba11-f8a1-42ad-915d-012ccb375e8a",
	//         "price": "2114.77",
	//         "qty": "0.01000",
	//         "quoteQty": "21.1477000",
	//         "time": 1775594995485,
	//         "isBuyerMaker": false,
	//         "isBestMatch": true
	//     }
	//
	// fetchMyTrades (spot)
	//     {
	//         "symbol": "DOGEUSDT",
	//         "id": 736825748291060702,
	//         "orderId": 736825748215563230,
	//         "price": "0.09349",
	//         "qty": "250.0",
	//         "quoteQty": "23.3725",
	//         "commission": "0.0233725",
	//         "time": 1775672947953,
	//         "isBuyer": false
	//     }
	//
	// fetchMyTrades (contract)
	//     {
	//         "id": 737074389731770728,
	//         "orderId": 737074043320009064,
	//         "symbol": "DOGEUSDT",
	//         "buyer": true,
	//         "commission": "0.00183500",
	//         "commissionAsset": "USDT",
	//         "maker": true,
	//         "price": "0.09175",
	//         "qty": "100",
	//         "quoteQty": "9.17500",
	//         "realizedPnl": "0",
	//         "side": "BUY",
	//         "positionSide": "LONG",
	//         "time": 1775732228692
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var timestamp any = this.SafeInteger(trade, "time")
	var isBuyer any = this.SafeBool(trade, "isBuyer")
	var side any = this.SafeStringLower(trade, "side")
	if IsTrue(!IsEqual(isBuyer, nil)) {
		side = Ternary(IsTrue(isBuyer), "buy", "sell")
	}
	var isSpot any = true
	if IsTrue(IsEqual(market, nil)) {
		var marketId any = this.SafeString(trade, "symbol")
		var realizedPnl any = this.SafeString(trade, "realizedPnl")
		var marketType any = Ternary(IsTrue((!IsEqual(realizedPnl, nil))), "swap", "spot")
		market = this.SafeMarket(marketId, nil, nil, marketType)
		isSpot = IsEqual(marketType, "spot")
	} else {
		isSpot = GetValue(market, "spot")
	}
	var fee any = nil
	var commission any = this.SafeString(trade, "commission")
	if IsTrue(!IsEqual(commission, nil)) {
		var commissionAsset any = this.SafeString(trade, "commissionAsset")
		var feeCurrency any = this.SafeCurrencyCode(commissionAsset)
		if IsTrue(isSpot) {
			if IsTrue(IsEqual(side, "buy")) {
				feeCurrency = GetValue(market, "base")
			} else {
				feeCurrency = GetValue(market, "quote")
			}
		}
		fee = map[string]any{
			"cost":     commission,
			"currency": feeCurrency,
		}
	}
	var isMaker any = this.SafeBool(trade, "maker")
	var takerOrMaker any = nil
	if IsTrue(!IsEqual(isMaker, nil)) {
		takerOrMaker = Ternary(IsTrue(isMaker), "maker", "taker")
	}
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"id":           this.SafeString(trade, "id"),
		"order":        this.SafeString(trade, "orderId"),
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       GetValue(market, "symbol"),
		"type":         nil,
		"takerOrMaker": takerOrMaker,
		"side":         side,
		"price":        this.SafeString(trade, "price"),
		"amount":       this.SafeString(trade, "qty"),
		"cost":         this.SafeString(trade, "quoteQty"),
		"fee":          fee,
	}, market)
}

