func (this *WeexCore) ParseLedgerEntry(item any, optionalArgs ...any) any {
	//
	// spot
	//     {
	//         "billId": "736825748291061726",
	//         "coinId": 82,
	//         "coinName": "DOGE",
	//         "bizType": "trade_out",
	//         "fillSize": "250.0",
	//         "fillValue": "23.372500",
	//         "deltaAmount": "-250.0",
	//         "afterAmount": "49.70000000",
	//         "fees": "0",
	//         "cTime": "1775672947953"
	//     }
	//
	// contract
	//     {
	//         "billId": 736791763716407518,
	//         "asset": "USDT",
	//         "symbol": null,
	//         "income": "-90.00000000",
	//         "incomeType": "withdraw",
	//         "balance": "106.00000000",
	//         "fillFee": "0",
	//         "time": 1775664845399,
	//         "transferReason": "UNKNOWN_TRANSFER_REASON"
	//     }
	//
	// funding
	//     {
	//         "billId": "16502414",
	//         "coinId": 2,
	//         "coinName": "USDT",
	//         "bizType": "transfer_out",
	//         "fillSize": null,
	//         "fillValue": null,
	//         "deltaAmount": "-100.00000000",
	//         "afterAmount": "0.00000000",
	//         "fees": "0.00000000",
	//         "cTime": "1775664588931"
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var currencyId any = this.SafeString2(item, "coinName", "asset")
	var code any = this.SafeCurrencyCode(currencyId, currency)
	currency = this.SafeCurrency(currencyId, currency)
	var timestamp any = this.SafeInteger2(item, "cTime", "time")
	var amountRaw any = this.SafeString2(item, "deltaAmount", "income")
	var after any = this.SafeString2(item, "afterAmount", "balance")
	var before any = Precise.StringSub(after, amountRaw)
	var amount any = this.ParseNumber(Precise.StringAbs(amountRaw))
	var direction any = "in"
	if IsTrue(IsGreaterThanOrEqual(GetIndexOf(amountRaw, "-"), 0)) {
		direction = "out"
	}
	var rawType any = this.SafeString2(item, "bizType", "incomeType")
	var transferReason any = this.SafeString(item, "transferReason")
	var isContractEntry any = (!IsEqual(transferReason, nil))
	if IsTrue(isContractEntry) {
		if IsTrue(IsTrue((IsEqual(rawType, "withdraw"))) || IsTrue((IsEqual(rawType, "deposit")))) {
			rawType = "transfer"
		}
	}
	return this.SafeLedgerEntry(map[string]any{
		"info":             item,
		"id":               this.SafeString(item, "billId"),
		"timestamp":        timestamp,
		"datetime":         this.Iso8601(timestamp),
		"direction":        direction,
		"account":          nil,
		"referenceId":      nil,
		"referenceAccount": nil,
		"type":             this.ParseLedgerType(rawType),
		"currency":         code,
		"amount":           amount,
		"before":           this.ParseNumber(before),
		"after":            this.ParseNumber(after),
		"status":           nil,
		"fee": map[string]any{
			"currency": code,
			"cost":     this.SafeNumber2(item, "fees", "fillFee"),
		},
	}, currency)
}
func (this *WeexCore) ParseLedgerType(typeVar any) any {
	var types any = map[string]any{
		"transfer_in":          "transfer",
		"transfer_out":         "transfer",
		"deposit":              "deposit",
		"withdraw":             "withdrawal",
		"trade_in":             "trade",
		"trade_out":            "trade",
		"position_open_long":   "trade",
		"position_open_short":  "trade",
		"position_close_long":  "trade",
		"position_close_short": "trade",
	}
	return this.SafeString(types, typeVar, typeVar)
}

