func (this *WeexCore) ParsePosition(position any, optionalArgs ...any) any {
	//
	//     {
	//         "id": 737191855967437160,
	//         "asset": "USDT",
	//         "symbol": "DOGEUSDT",
	//         "side": "LONG",
	//         "marginType": "CROSSED",
	//         "separatedMode": "COMBINED",
	//         "separatedOpenOrderId": 0,
	//         "leverage": "20.00",
	//         "size": "300",
	//         "openValue": "27.96900",
	//         "openFee": "0.02237520",
	//         "fundingFee": "0",
	//         "marginSize": "100",
	//         "isolatedMargin": "0",
	//         "isAutoAppendIsolatedMargin": false,
	//         "cumOpenSize": "300",
	//         "cumOpenValue": "27.96900",
	//         "cumOpenFee": "0.02237520",
	//         "cumCloseSize": "0",
	//         "cumCloseValue": "0",
	//         "cumCloseFee": "0",
	//         "cumFundingFee": "0",
	//         "cumLiquidateFee": "0",
	//         "createdMatchSequenceId": 5762536243,
	//         "updatedMatchSequenceId": 5762741613,
	//         "createdTime": 1775760234825,
	//         "updatedTime": 1775763170789,
	//         "unrealizePnl": "0.00600",
	//         "liquidatePrice": "0"
	//     }
	//
	// watchPoisions
	//     {
	//         "id": "739004481374519656",
	//         "coin": "USDT",
	//         "symbol": "DOGEUSDT",
	//         "side": "LONG",
	//         "marginMode": "CROSSED",
	//         "separatedMode": "COMBINED",
	//         "separatedOpenOrderId": "0",
	//         "leverage": "11",
	//         "size": "100",
	//         "openValue": "9.31100",
	//         "openFee": "0.00744880",
	//         "fundingFee": "0",
	//         "isolatedMargin": "0",
	//         "autoAppendIsolatedMargin": false,
	//         "cumOpenSize": "100",
	//         "cumOpenValue": "9.31100",
	//         "cumOpenFee": "0.00744880",
	//         "cumCloseSize": "0",
	//         "cumCloseValue": "0",
	//         "cumCloseFee": "0",
	//         "cumFundingFee": "0",
	//         "cumLiquidateFee": "0",
	//         "createdMatchSequenceId": "5792711540",
	//         "updatedMatchSequenceId": "5792711540",
	//         "createdTime": "1776192398399",
	//         "updatedTime": "1776192398399"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var errorMessage any = this.SafeString(position, "errorMsg")
	var errorCode any = this.SafeString(position, "errorCode")
	if IsTrue(!IsEqual(errorMessage, nil)) {
		this.HandleOrderOrPositionError(errorCode, errorMessage, position)
	}
	var marketId any = this.SafeString2(position, "symbol", "coinId") // coinId might be used in testnet: https://github.com/ccxt/ccxt/issues/28576#issuecomment-4439400273
	market = this.SafeMarket(marketId, market, nil, "contract")
	var timestamp any = this.SafeInteger(position, "createdTime")
	var marginType any = this.SafeString2(position, "marginType", "marginMode")
	var marginMode any = "cross"
	if IsTrue(IsEqual(marginType, "ISOLATED")) {
		marginMode = "isolated"
	}
	var separatedMode any = this.SafeString(position, "separatedMode")
	var hedged any = nil
	if IsTrue(IsEqual(separatedMode, "COMBINED")) {
		hedged = false
	} else if IsTrue(IsEqual(separatedMode, "SEPARATED")) {
		hedged = true
	}
	var notional any = this.SafeString(position, "openValue")
	var size any = this.SafeString(position, "size")
	var entryPrice any = Precise.StringDiv(notional, size)
	return this.SafePosition(map[string]any{
		"symbol":                      GetValue(market, "symbol"),
		"id":                          this.SafeString2(position, "id", "positionId"),
		"timestamp":                   timestamp,
		"datetime":                    this.Iso8601(timestamp),
		"contracts":                   this.ParseNumber(size),
		"contractSize":                nil,
		"side":                        this.SafeStringLower(position, "side"),
		"notional":                    this.ParseNumber(notional),
		"leverage":                    this.SafeNumber(position, "leverage"),
		"unrealizedPnl":               this.SafeNumber(position, "unrealizePnl"),
		"realizedPnl":                 nil,
		"collateral":                  nil,
		"entryPrice":                  this.ParseNumber(entryPrice),
		"markPrice":                   nil,
		"liquidationPrice":            this.SafeNumber(position, "liquidatePrice"),
		"marginMode":                  marginMode,
		"hedged":                      hedged,
		"maintenanceMargin":           nil,
		"maintenanceMarginPercentage": nil,
		"initialMargin":               this.SafeNumber(position, "marginSize"),
		"initialMarginPercentage":     nil,
		"marginRatio":                 nil,
		"lastUpdateTimestamp":         this.SafeInteger(position, "updatedTime"),
		"lastPrice":                   nil,
		"stopLossPrice":               nil,
		"takeProfitPrice":             nil,
		"percentage":                  nil,
		"info":                        position,
	})
}

